 1	import { type FC, useCallback, useMemo, useState } from 'react';
 2	import { loadUserSettings } from 'src/components/common/Page/userSettings';
 3	import { StandardPageWithSelection } from 'src/components/page/StandardPageWithSelection';
 4	import { TableSortContextProvider } from 'src/components/TableSortContext';
 5	import { isPlanExecuting } from 'src/plans/details/components/PlanStatus/utils/utils';
 6	import { useForkliftTranslation } from 'src/utils/i18n';
 7	
 8	import { INITIAL_PAGE } from '@components/page/utils/constants';
 9	import type { V1beta1Plan } from '@kubev2v/types';
10	
11	import { PLAN_VIRTUAL_MACHINES_LIST_ID } from '../utils/constants';
12	
13	import MigrationStatusExpandedPage from './components/MigrationStatusExpandedPage/MigrationStatusExpandedPage';
14	import { useMigrationResources } from './hooks/useMigrationResources';
15	import { useMigrationVirtualMachineActions } from './hooks/useMigrationVirtualMachineActions';
16	import { planMigrationVirtualMachinesFields } from './utils/constants';
17	import type { MigrationStatusVirtualMachinePageData } from './utils/types';
18	import MigrationStatusVirtualMachinesRow from './MigrationStatusVirtualMachinesRow';
19	
20	type MigrationStatusVirtualMachinesListProps = {
21	  plan: V1beta1Plan;
22	};
23	
24	const selectedIds: string[] = [];
25	
26	const onSelect = () => undefined;
27	
28	const toId = (item: MigrationStatusVirtualMachinePageData) => item?.specVM?.id ?? '';
29	
30	const MigrationStatusVirtualMachinesList: FC<MigrationStatusVirtualMachinesListProps> = ({
31	  plan,
32	}) => {
33	  const { t } = useForkliftTranslation();
34	  const userSettings = useMemo(
35	    () => loadUserSettings({ pageId: PLAN_VIRTUAL_MACHINES_LIST_ID }),
36	    [],
37	  );
38	  const { migrationListData } = useMigrationResources(plan);
39	  const actions = useMigrationVirtualMachineActions(plan);
40	  const [expandedIds, setExpandedIds] = useState<string[]>([]);
41	
42	  const isExecuting = isPlanExecuting(plan);
43	
44	  const canSelectWhenExecuting = useCallback(
45	    (item: MigrationStatusVirtualMachinePageData) =>
46	      item?.statusVM?.completed === undefined && isExecuting,
47	    [isExecuting],
48	  );
49	
50	  const canSelectWhenNotExecuting = useCallback(
51	    (item: MigrationStatusVirtualMachinePageData) =>
52	      (item?.statusVM?.started === undefined || item?.statusVM?.error !== undefined) &&
53	      !isExecuting,
54	    [isExecuting],
55	  );
56	
57	  const dataSource: [MigrationStatusVirtualMachinePageData[], boolean, unknown] = useMemo(
58	    () => [migrationListData ?? [], true, undefined],
59	    [migrationListData],
60	  );
61	
62	  const canSelect = useCallback(
63	    (item: MigrationStatusVirtualMachinePageData) =>
64	      canSelectWhenExecuting(item) ?? canSelectWhenNotExecuting(item),
65	    [canSelectWhenExecuting, canSelectWhenNotExecuting],
66	  );
67	  return (
68	    <TableSortContextProvider fields={planMigrationVirtualMachinesFields}>
69	      <StandardPageWithSelection<MigrationStatusVirtualMachinePageData>
70	        canSelect={canSelect}
71	        CellMapper={MigrationStatusVirtualMachinesRow}
72	        dataSource={dataSource}
73	        ExpandedComponent={MigrationStatusExpandedPage}
74	        expandedIds={expandedIds}
75	        fieldsMetadata={planMigrationVirtualMachinesFields}
76	        GlobalActionToolbarItems={actions}
77	        namespace={''}
78	        onExpand={setExpandedIds}
79	        onSelect={onSelect}
80	        page={INITIAL_PAGE}
81	        selectedIds={selectedIds}
82	        title={t('Virtual machines')}
83	        toId={toId}
84	        userSettings={userSettings}
85	      />
86	    </TableSortContextProvider>
87	  );
88	};
89	
90	export default MigrationStatusVirtualMachinesList;

